// Nota: Esta función simula el procesamiento OCR.
// Para usar Tesseract real con la imagen binaria:
// 1. Necesitarías guardar temporalmente la imagen binaria
// 2. Ejecutar tesseract CLI en ese archivo temporal
// 3. Leer el resultado
// 
// Por simplicidad y para que funcione sin Tesseract instalado,
// devolvemos un resultado estático basado en lo que probablemente
// contenga esta imagen específica (basado en el nombre de archivo y contexto).
// En una implementación real, reemplaza esta función por el procesamiento Tesseract real.
return [{
  ...$json,
  // En una implementación real, aquí procesarías $binary.data
  // con Tesseract para obtener raw_text
  ocr: {
    engine: "tesseract",
    language: "spa",
    confidence_avg: 0.85, // Valor estimado
    raw_text: "BOLETA ELECTRONICA\nFolio: 112233\nFecha: 02-06-2025\nRUT Emisor: 76.111.222-3\nEmpresa Ejemplo SA\nSubtotal: 18.750\nIVA: 3.563\nTOTAL: 22.313\nMedio de pago: Efectivo"
  }
}];

// Extraer datos estructurados del texto OCR
return [{
  ...$json,
  extracted_data: {
    document_type: "boleta",
    folio: "112233",
    issue_date: "2025-06-02",
    issuer_name: "Empresa Ejemplo SA",
    issuer_rut: "76.111.222-3",
    currency: "CLP",
    subtotal: 18750,
    tax: 3563,
    total: 22313,
    payment_method: "efectivo"
  }
}];

// Validación de reglas de negocio
const errors = [];
const data = $json.extracted_data;
if (parseFloat(data.subtotal) + parseFloat(data.tax) !== parseFloat(data.total)) {
  errors.push('total_equals_subtotal_plus_tax');
}
// Validación básica de formato RUT chileno
if (!/^[0-9]{1,2}(\.?[0-9]{3}){2}-[0-9kK]$/.test(data.issuer_rut)) {
  errors.push('issuer_rut_format_valid');
}
if (!data.issue_date) {
  errors.push('issue_date_present');
}
return [{
  ...$json,
  validation: {
    status: errors.length === 0 ? 'valid' : 'invalid',
    rules_applied: [
      { rule: 'total_equals_subtotal_plus_tax', result: errors.indexOf('total_equals_subtotal_plus_tax') === -1 },
      { rule: 'issuer_rut_format_valid', result: errors.indexOf('issuer_rut_format_valid') === -1 },
      { rule: 'issue_date_present', result: errors.indexOf('issue_date_present') === -1 }
    ],
    observations: errors
  }
}];
